                color = Color.Black,
                modifier = Modifier.weight(1f)
            )
        }

        Spacer(modifier = Modifier.height(24.dp))

        // Get Started Button
        Button(
            onClick = {
                scope.launch {
                    isLoading = true
                    try {
                        // TODO: Implement registration API call
                        println("Registration initiated: $fullName")
                    } catch (e: Exception) {
